export const fetchInitialData = async (): Promise<AppState> => {
    if (!isSupabaseConfigured()) throw new Error("Supabase is not configured.");

    const [usersRes, annRes, tasksRes] = await Promise.all([
        supabase.from('users').select('*'),
        supabase.from('announcements').select('*').order('date', { ascending: false }),
        supabase.from('direct_tasks').select('*').order('sent_at', { ascending: false })
    ]);

    // Smart Fetch Strategy for Reports
    let reportsData: any[] = [];

    // Attempt 1: Fetch full reports (limit to 300 to avoid massive payloads)
    const { data: fullData, error: fullError } = await supabase
        .from('reports')
        .select('*')
        .order('date', { ascending: false })
        .limit(300);

    if (fullError) {
        console.warn("Full reports fetch failed, attempting partial fetch...", fullError);

        // Attempt 2: Fetch reports WITHOUT attachments column (lightweight fallback)
        const { data: lightData, error: lightError } = await supabase
            .from('reports')
            .select('id, user_id, sequence_number, date, day, tasks, accomplished, not_accomplished, manager_comment, is_viewed_by_manager, is_comment_read_by_employee, rating, status')
            .order('date', { ascending: false })
            .limit(300);

        if (lightError) {
            console.error("Critical: Failed to fetch reports even with partial selection.", JSON.stringify(lightError));
        } else {
            reportsData = lightData || [];
        }
    } else {
        reportsData = fullData || [];
    }

