import { ThemeProvider } from './context/ThemeContext';
import ExclamationCircleIcon from './components/icons/ExclamationCircleIcon';
import InstallPWA from './components/InstallPWA';

const AppContent: React.FC = () => {
    const { currentUser, loading: authLoading } = useAuth();
    const { isDataLoading, error } = useData();

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 dark:bg-gray-900 p-4 text-center">
                 <div className="bg-white dark:bg-gray-800 p-8 rounded-lg shadow-xl max-w-md w-full border border-red-200 dark:border-red-900">
                    <ExclamationCircleIcon className="w-16 h-16 text-red-500 mx-auto mb-4" />
                    <h2 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-2">خطأ في الاتصال</h2>
                    <p className="text-gray-600 dark:text-gray-300 mb-6">{error}</p>

                    {error.includes('relation') && (
                        <div className="text-sm text-left bg-gray-100 dark:bg-gray-700 p-3 rounded mb-4 overflow-x-auto text-gray-700 dark:text-gray-300">
                            <p className="font-semibold mb-1">الحل المقترح:</p>
                            <p>يبدو أن جداول قاعدة البيانات غير موجودة. يرجى الذهاب إلى Supabase SQL Editor وتشغيل الكود لإنشاء الجداول.</p>
                        </div>
                    )}

                    <button 
                        onClick={() => window.location.reload()}
                        className="w-full px-4 py-2 bg-brand-light text-white rounded hover:bg-brand-dark transition-colors"
                    >
                        إعادة المحاولة
                    </button>
                 </div>
            </div>
        );
    }

    if (authLoading || isDataLoading) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-100 dark:bg-gray-900">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-brand-light border-t-transparent rounded-full animate-spin mb-4"></div>
                    <div className="text-xl font-semibold text-gray-700 dark:text-gray-300">جاري الاتصال بقاعدة البيانات...</div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
            {!currentUser ? <Login /> : (currentUser.role === 'employee' ? <EmployeeDashboard /> : <ManagerDashboard />)}
            <InstallPWA />
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ThemeProvider>
            <DataProvider>
                <AuthProvider>
                    <AppContent />
                </AuthProvider>
            </DataProvider>
        </ThemeProvider>
    );
};

export default App;

import React, { createContext, useState, useContext, ReactNode, useMemo, useCallback, useEffect, useRef } from 'react';
import { User, Report, Announcement, DirectTask } from '../types';
import * as api from '../services/apiService';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
}

interface DataContextType extends AppState {
    isDataLoading: boolean;
    isCloud: boolean;
    error: string | null;
    isSyncing: boolean;
    refreshData: () => Promise<void>;
    notification: { message: string, type: 'info' | 'success', id: number } | null;
    clearNotification: () => void;
    getUserById: (id: string) => User | undefined;
    addReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => Promise<void>;
    submitReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>, draftId?: string) => Promise<void>;
    updateReport: (updatedReport: Report) => Promise<void>;
    saveOrUpdateDraft: (draft: Partial<Report>) => Promise<void>;
    deleteReport: (reportId: string) => Promise<void>;
    markReportAsViewed: (reportId: string) => Promise<void>;
    markAllReportsAsReadForUser: (userId: string) => Promise<void>;
    markCommentAsRead: (reportId: string) => Promise<void>;
    addUser: (user: Omit<User, 'id'>) => Promise<void>;
    updateUser: (user: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addAnnouncement: (content: string) => Promise<void>;
    updateAnnouncement: (announcementId: string, content: string) => Promise<void>;
    deleteAnnouncement: (announcementId: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string, userId: string) => Promise<void>;
    addDirectTask: (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => Promise<void>;
    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
    unlockAudio: () => void;
    testNotification: () => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [appState, setAppState] = useState<AppState>({ users: [], reports: [], announcements: [], directTasks: [] });
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCloud, setIsCloud] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [notification, setNotification] = useState<{ message: string, type: 'info' | 'success', id: number } | null>(null);

    const audioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3');
        audioRef.current.load();
    }, []);

    const unlockAudio = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.play().then(() => {
                audioRef.current?.pause();
                if (audioRef.current) audioRef.current.currentTime = 0;
            }).catch(e => console.log("Audio interaction needed"));
        }
    }, []);

    const playNotificationSound = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.currentTime = 0;
            audioRef.current.volume = 0.6;
            audioRef.current.play().catch(e => console.warn("Sound blocked"));
        }
    }, []);

    const triggerNotification = useCallback((title: string, body: string, type: 'info' | 'success' = 'info') => {
        setNotification({ message: body, type, id: Date.now() });
        playNotificationSound();

        if ("vibrate" in navigator) {
            navigator.vibrate([100, 50, 100]);
        }

        if ("Notification" in window && Notification.permission === "granted") {
            const options: any = {
                body,
                icon: 'https://img.icons8.com/fluency/192/task.png',
                vibrate: [200, 100, 200],
            };
            navigator.serviceWorker.ready.then(reg => reg.showNotification(title, options));
        }
    }, [playNotificationSound]);

    const testNotification = useCallback(() => {
        triggerNotification("تجربة النظام", "أهلاً بك، نظام التنبيهات يعمل بنجاح.", "success");
    }, [triggerNotification]);

    const clearNotification = useCallback(() => setNotification(null), []);

    const loadData = useCallback(async (silent = false) => {
        if (!silent) setIsDataLoading(true);
        else setIsSyncing(true);
        try {
            const data = await api.fetchInitialData();
            setAppState({
                users: data.users,
                reports: data.reports,
                announcements: data.announcements,
                directTasks: data.directTasks
            });
            setIsCloud(data.isCloud);
        } catch (error: any) {
            if (!silent) setError(error.message || "خطأ اتصال.");
        } finally {
            setIsDataLoading(false);
            setIsSyncing(false);
        }
    }, []);

    const refreshData = useCallback(async () => {
        await loadData(true);
    }, [loadData]);

    useEffect(() => {
        loadData();
        const unsubscribe = api.subscribeToAllChanges((payload) => {
            const { table, eventType, new: newRecord } = payload;
            setAppState(prev => {
                const newState = { ...prev };
                const loggedInUserId = localStorage.getItem('loggedInUserId') || sessionStorage.getItem('loggedInUserId');
                const currentUser = prev.users.find(u => u.id === loggedInUserId);

                if (table === 'reports') {
                    if (eventType === 'INSERT' || eventType === 'UPDATE') {
                        const mapped = api.mapReport(newRecord);

                        // Capture the previous version of the report to detect changes
                        const previousReport = prev.reports.find(r => r.id === mapped.id);

                        newState.reports = prev.reports.map(r => r.id === mapped.id ? mapped : r);
                        if (eventType === 'INSERT') newState.reports = [mapped, ...newState.reports];

                        // Notification 1: New Report for Manager
                        if (eventType === 'INSERT' && mapped.status === 'submitted' && currentUser?.role === 'manager') {
                            const sender = prev.users.find(u => u.id === mapped.userId);
                            triggerNotification('تقرير جديد', `وصل تقرير جديد من ${sender?.fullName.split(' ')[0]}`, 'success');
                        }

                        // Notification 2: New/Updated Manager Comment for Employee
                        if (eventType === 'UPDATE' && currentUser && currentUser.id === mapped.userId) {
                             const oldComment = previousReport?.managerComment;
                             const newComment = mapped.managerComment;

                             // Check if comment was added or changed (and is not empty)
                             if (newComment && newComment.trim().length > 0 && newComment !== oldComment) {
                                 triggerNotification('توجيه إداري جديد', `تم إضافة توجيه على تقريرك بتاريخ ${mapped.date}`, 'info');
                             }
                        }
                    }
                } else if (table === 'direct_tasks') {
                     if (eventType === 'INSERT') {
                         const newTask = api.mapDirectTask(newRecord);
                         newState.directTasks = [newTask, ...prev.directTasks];

                         if (currentUser && newTask.employeeId === currentUser.id) {
                              const manager = prev.users.find(u => u.id === newTask.managerId);
                              triggerNotification('مهمة جديدة', `وصلتك مهمة جديدة من ${manager?.fullName || 'المسؤول'}`, 'info');
                         }
                     } else if (eventType === 'UPDATE') {
                         const updatedTask = api.mapDirectTask(newRecord);
                         newState.directTasks = prev.directTasks.map(t => t.id === updatedTask.id ? updatedTask : t);
                     }
                } else if (table === 'announcements') {
                     if (eventType === 'INSERT') {
                         const newAnn = api.mapAnnouncement(newRecord);
                         newState.announcements = [newAnn, ...prev.announcements];
                         if (currentUser && currentUser.role === 'employee') {
                             triggerNotification('توجيه عام جديد', 'تم نشر توجيه عام جديد من الإدارة', 'info');
                         }
                     } else if (eventType === 'UPDATE') {
                         const updatedAnn = api.mapAnnouncement(newRecord);
                         newState.announcements = prev.announcements.map(a => a.id === updatedAnn.id ? updatedAnn : a);
                     }
                } else if (table === 'users') {
                     if (eventType === 'INSERT' || eventType === 'UPDATE') {
                         const mappedUser = api.mapUser(newRecord);
                         newState.users = prev.users.map(u => u.id === mappedUser.id ? mappedUser : u);
                         if (eventType === 'INSERT') newState.users = [...prev.users, mappedUser];
                     }
                }

                return newState;
            });
        });
        return () => { unsubscribe(); };
    }, [loadData, triggerNotification]);

    const getUserById = useCallback((id: string) => appState.users.find(u => u.id === id), [appState.users]);
    const saveOrUpdateDraft = useCallback(async (draft: Partial<Report>) => { try { await api.saveOrUpdateDraft(draft); } catch (e) { throw e; } }, []);
    const addReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => { try { await api.createReport(report); } catch (e) { throw e; } }, []);
    const submitReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>, draftId?: string) => { try { await api.submitReport(report, draftId); } catch (e) { throw e; } }, []);
    const updateReport = useCallback(async (updatedReport: Report) => { try { await api.updateReport(updatedReport); } catch (e) { throw e; } }, []);
    const deleteReport = useCallback(async (reportId: string) => { try { await api.deleteReport(reportId); } catch (e) { throw e; } }, []);
    const markReportAsViewed = useCallback(async (reportId: string) => { 
        // تحديث محلي فوري
        setAppState(prev => ({
            ...prev,
            reports: prev.reports.map(r => r.id === reportId ? { ...r, isViewedByManager: true } : r)
        }));
        await api.markReportAsViewed(reportId); 
    }, []);
    const markAllReportsAsReadForUser = useCallback(async (userId: string) => { 
        // تحديث محلي فوري لجميع تقارير المستخدم
        setAppState(prev => ({
            ...prev,
            reports: prev.reports.map(r => r.userId === userId ? { ...r, isViewedByManager: true } : r)
        }));
        await api.markAllReportsAsReadForUser(userId); 
    }, []);
    const markCommentAsRead = useCallback(async (reportId: string) => { await api.markCommentAsRead(reportId); }, []);
    const addUser = useCallback(async (user: Omit<User, 'id'>) => api.createUser(user), []);
    const updateUser = useCallback(async (updatedUser: User) => api.updateUser(updatedUser), []);
    const deleteUser = useCallback(async (userId: string) => api.deleteUser(userId), []);
    const addAnnouncement = useCallback(async (content: string) => api.createAnnouncement(content), []);
    const updateAnnouncement = useCallback(async (annId: string, content: string) => api.updateAnnouncement(annId, content), []);
    const deleteAnnouncement = useCallback(async (annId: string) => api.deleteAnnouncement(annId), []);
    const markAnnouncementAsRead = useCallback(async (annId: string, uId: string) => api.markAnnouncementAsRead(annId, uId), []);
    const addDirectTask = useCallback(async (task: any) => api.createDirectTask(task), []);
    const updateDirectTaskStatus = useCallback(async (tId: string, s: any, r?: string) => api.updateDirectTaskStatus(tId, s, r), []);
    const markDirectTaskAsRead = useCallback(async (tId: string) => api.markDirectTaskAsRead(tId), []);

    const value = useMemo(() => ({
        ...appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, 
        addReport, submitReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification
    }), [appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, 
        addReport, submitReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification]);

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = (): DataContextType => {
    const context = useContext(DataContext);
    if (!context) throw new Error('useData error');
    return context;
};

import React, { useState, useMemo } from 'react';
import { Report, User, Role, Attachment } from '../types';
import { useData } from '../context/DataContext';
import TrashIcon from './icons/TrashIcon';
import DocumentTextIcon from './icons/DocumentTextIcon';
import XMarkIcon from './icons/XMarkIcon';
import DownloadIcon from './icons/DownloadIcon';
import AIReportAnalysis from './AIReportAnalysis';
import CheckBadgeIcon from './icons/CheckBadgeIcon';

interface ReportDetailProps {
    report: Report;
    user: User;
    viewerRole: Role;
    hideMargin?: boolean;
}

const ReportDetail: React.FC<ReportDetailProps> = ({ report: initialReport, user, viewerRole, hideMargin = false }) => {
    const { updateReport, users } = useData();
    const [report, setReport] = useState<Report>(initialReport);
    const [isEditingComment, setIsEditingComment] = useState(false);
    const [comment, setComment] = useState(report.managerComment || '');
    const [previewAttachment, setPreviewAttachment] = useState<Attachment | null>(null);
    const [isSaving, setIsSaving] = useState(false);

    const isManager = viewerRole === Role.MANAGER;

    const manager = useMemo(() => {
        return users.find(u => u.role === Role.MANAGER) || { fullName: 'مسؤول الشعبة' };
    }, [users]);

    const handleTaskDelete = async (taskId: string) => {
        const taskComment = prompt("سبب الحذف:");
        if (taskComment !== null) {
            const updatedTasks = report.tasks.map(task => 
                task.id === taskId ? { ...task, isDeleted: true, managerComment: taskComment } : task
            );
            const updatedReport = { ...report, tasks: updatedTasks };
            setReport(updatedReport);
            await updateReport(updatedReport);
        }
    };

    const handleSaveManagerComment = async () => {
        setIsSaving(true);
        const updatedReport = { ...report, managerComment: comment };
        setReport(updatedReport);
        setIsEditingComment(false);
        await updateReport(updatedReport);
        setIsSaving(false);
    };

    // وظيفة الاطلاع السريع (الزر الجديد)
    const handleQuickAcknowledge = async (e: React.MouseEvent) => {
        e.stopPropagation(); // منع فتح وضع التعديل عند الضغط على الزر
        setIsSaving(true);
        const timestamp = new Date().toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' });
        const quickComment = `تم الاطلاع، يعطيكم العافية ✅\n(${timestamp})`;

        setComment(quickComment);
        const updatedReport = { ...report, managerComment: quickComment };
        setReport(updatedReport);
        await updateReport(updatedReport);
        setIsSaving(false);
    };

    return (
        <div className="w-full flex flex-col space-y-8 p-4 sm:p-8 md:p-10 bg-inherit text-right" dir="rtl">

            {/* 1. قسم المهام اليومية - جدول كامل العرض لمنع التداخل */}
            <section className="w-full block overflow-hidden">
                <div className="flex items-center mb-3 border-r-4 border-brand-light pr-3">
                    <h4 className="text-xs md:text-sm font-bold text-brand-dark dark:text-brand-light uppercase tracking-wide">
                        بيان المهام والنشاطات اليومية المنجزة
                    </h4>
                </div>
                <div className="w-full bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-xl shadow-sm overflow-x-auto">
                    <table className="w-full border-collapse">
                        <thead>
                            <tr className="bg-gray-50 dark:bg-gray-700/50 border-b dark:border-gray-600">
                                <th className="px-4 py-3 text-[11px] font-bold text-gray-600 dark:text-gray-300 w-12 text-center border-l dark:border-gray-600">ت</th>
                                <th className="px-4 py-3 text-[11px] font-bold text-gray-600 dark:text-gray-300 text-right">وصف المهمة</th>
                                {isManager && <th className="px-4 py-3 text-[11px] font-bold text-gray-600 dark:text-gray-300 w-20 text-center no-print">إجراء</th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y dark:divide-gray-700">
                            {report.tasks.map((task, idx) => (
                                <tr key={task.id} className={`${task.isDeleted ? 'bg-red-50/30' : 'hover:bg-gray-50/50'} transition-colors`}>
                                    <td className="px-4 py-3 text-[11px] text-center font-bold text-gray-400 border-l dark:border-gray-600">{idx + 1}</td>
                                    <td className="px-4 py-3">
                                        <p className={`text-[12px] md:text-[13px] leading-relaxed ${task.isDeleted ? 'line-through text-gray-400' : 'text-gray-800 dark:text-gray-200'}`}>
                                            {task.text}
                                        </p>
                                        {task.isDeleted && task.managerComment && (
                                            <p className="mt-1 text-[10px] text-red-500 font-bold italic">ملاحظة المسؤول: {task.managerComment}</p>
                                        )}
                                    </td>
                                    {isManager && (
                                        <td className="px-4 py-3 text-center no-print">
                                            {!task.isDeleted && (
                                                <button onClick={() => handleTaskDelete(task.id)} className="text-red-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded-lg transition-all">
                                                    <TrashIcon className="w-4 h-4" />
                                                </button>
                                            )}
                                        </td>
                                    )}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </section>

            {/* 2. قسم التفاصيل الإضافية - عرض عمودي مرتب */}
            <div className="flex flex-col md:flex-row gap-6">
                <section className="flex-1 bg-gray-50 dark:bg-gray-800/50 p-5 rounded-2xl border dark:border-gray-700">
                    <h4 className="text-[10px] font-bold text-gray-400 mb-2 uppercase border-b dark:border-gray-700 pb-1">خلاصة الإنجاز</h4>
                    <p className="text-[12px] md:text-[13px] text-gray-800 dark:text-gray-200 leading-relaxed whitespace-pre-wrap">{report.accomplished || 'لا توجد بيانات'}</p>
                </section>
                <section className="flex-1 bg-gray-50 dark:bg-gray-800/50 p-5 rounded-2xl border dark:border-gray-700">
                    <h4 className="text-[10px] font-bold text-gray-400 mb-2 uppercase border-b dark:border-gray-700 pb-1">المعوقات والمقترحات</h4>
                    <p className="text-[12px] md:text-[13px] text-gray-800 dark:text-gray-200 leading-relaxed whitespace-pre-wrap">{report.notAccomplished || 'لا توجد معوقات'}</p>
                </section>
            </div>

            {/* 3. هامش المسؤول - تصميم إداري نظيف */}
            {!hideMargin && (
                <section className="print-page-break block w-full">
                    <div className="flex items-center mb-3 border-r-4 border-brand-light pr-3">
                        <h4 className="text-xs font-bold text-brand-dark dark:text-brand-light uppercase">هامش وتوجيهات مسؤول الشعبة</h4>
                    </div>
                    <div className={`p-6 rounded-3xl border-2 transition-all relative ${report.managerComment ? 'bg-green-50/20 border-green-100 dark:border-green-900/10' : 'bg-gray-50 border-dashed border-gray-300 dark:border-gray-700'}`}>
                        {isManager && isEditingComment ? (
                            <div className="no-print space-y-4">
                                <textarea
                                    value={comment}
                                    onChange={(e) => setComment(e.target.value)}
                                    rows={3}
                                    className="w-full p-4 text-xs md:text-sm bg-white dark:bg-gray-700 border-gray-200 dark:border-gray-600 rounded-xl outline-none focus:ring-2 focus:ring-brand-light"
                                    placeholder="اكتب التوجيهات هنا..."
                                />
                                <div className="flex justify-end gap-2">
                                    <button onClick={() => setIsEditingComment(false)} className="text-xs text-gray-500 px-3">إلغاء</button>
                                    <button onClick={handleSaveManagerComment} disabled={isSaving} className="px-6 py-2 bg-brand-light text-white rounded-xl font-bold text-xs shadow-md">
                                        {isSaving ? 'جارِ الحفظ...' : 'حفظ التوجيه'}
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div onClick={() => isManager && setIsEditingComment(true)} className={`${isManager ? 'cursor-pointer group' : ''}`}>
                                <p className={`text-xs md:text-sm leading-relaxed whitespace-pre-wrap italic ${!report.managerComment ? 'text-gray-400' : 'text-gray-800 dark:text-gray-100'}`}>
                                    {report.managerComment || (isManager ? 'انقر لكتابة ملاحظة يدوية...' : 'لم يتم إضافة توجيهات بعد.')}
                                </p>

                                {/* زر الاطلاع السريع للمدير - يظهر فقط إذا لم يكن هناك تعليق */}
                                {isManager && !report.managerComment && (
                                    <div className="mt-6 flex justify-center no-print">
                                        <button 
                                            onClick={handleQuickAcknowledge}
                                            disabled={isSaving}
                                            className="flex items-center gap-2 px-6 py-3 bg-brand-light text-white rounded-full font-bold shadow-lg shadow-brand-light/30 hover:scale-105 active:scale-95 transition-all hover:bg-brand-dark"
                                        >
                                            {isSaving ? (
                                                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                                            ) : (
                                                <CheckBadgeIcon className="w-6 h-6" />
                                            )}
                                            <span>تم الاطلاع والاعتماد</span>
                                        </button>
                                    </div>
                                )}

                                {report.managerComment && (
