                    message="هل أنت متأكد من حذف هذا التقرير؟"
                    onConfirm={handleDelete}
                    onCancel={() => setShowDeleteConfirm(false)}
                    confirmText="حذف"
                    confirmButtonClass="bg-red-600"
                />
            )}
        </div>
    );
};

