            </div>

            {/* نافذة التفاصيل المنبثقة بتصميم جديد */}
            {activeDetail && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md p-4 animate-fade-in" onClick={() => setActiveDetail(null)}>
